#include "TriggerCommand.h"
#include "FL_TriggerJson.h"
namespace FLTriggers { TriggerCommand::TriggerCommand():point_(CCPointZero),amount_(0),enabled_(false),alternate_(false){}void TriggerCommand::load(const std::string&i,const flrapidjson::Value&j){Trigger::load(i,j);type_=Json::lower(Json::scalar(j,"Type"));if(type_=="spawntrigger")value_=Json::scalar(j,"spawnGroupID");else if(type_=="triggereventcameralimit")value_=Json::scalar(j,"limitType");else if(type_=="triggereventweather")value_=Json::scalar(j,"weatherType");else if(type_=="triggereventlightning")value_=Json::scalar(j,"lightningType");else if(type_=="triggereventsound"){value_=Json::scalar(j,"soundName");secondary_=Json::scalar(j,"soundID");}else if(type_=="tetutorialpopup")value_=Json::scalar(j,"tutorialImage");else if(type_=="triggertutorial")value_=Json::scalar(j,"textID");else if(type_=="triggershop")value_=Json::scalar(j,"shopImg");else if(type_=="triggerdialog"){value_=Json::scalar(j,"passGroup");secondary_=Json::scalar(j,"failGroup");}point_=Json::point(j,"buttonPosition",Json::point(j,"position"));amount_=Json::number(j,"opacity",Json::number(j,"duration",Json::number(j,"textDuration")));enabled_=Json::boolean(j,"toggleON",!Json::boolean(j,"resetLimit"));alternate_=Json::boolean(j,"isBG",Json::boolean(j,"pauseCM",Json::boolean(j,"resumeCM")));if(type_=="triggereventfalldeath"||type_=="triggereventsafespot")callOnlyOnce_=false;}void TriggerCommand::activateTrigger(TriggerSystem&s,FL_TriggerHost&h){h.triggerCommand(type_,value_,secondary_,point_,amount_,enabled_,alternate_);if(type_=="triggerdialog"&&!value_.empty())s.activateGroup(value_,GroupActivate,true,false,h);if(type_=="tetutorialpopup"&&!callGroupID_.empty()&&callGroupID_!="0")s.activateGroup(callGroupID_,GroupActivate,true,false,h);} }
